/**
 * Hook Trigger: after_user_create
 * Description: Fetches full user details (including metadata) and seeds the profile collection.
 */
export default async function(req) {
  const eventData = req.data; // { id: number, email: string, role: string }

  // 1. Fetch full user object to obtain the registration metadata
  const user = await $db.users.get(eventData.email);
  if (!user) {
    console.error(`[after_user_create] Unable to resolve user details for email: ${eventData.email}`);
    return;
  }

  const meta = user.metadata || {};

  // 2. Prepare the users_profiles record payload
  const profilePayload = {
    user_id: user.id, // Relational owner field linking to the core user
    email: user.email,
    name: meta.name || user.email.split('@')[0],
    role: user.role,
    avatar: meta.avatar || `https://api.dicebear.com/7.x/pixel-art/svg?seed=${user.id}`,
    bio: meta.bio || '',
    expertise: meta.expertise || [],
    hourlyRate: Number(meta.hourlyRate) || 35,
    completedTasks: 0,
    balance: user.role === 'student' ? 300 : 0, // Balance initialization
    reviewsCount: 0,
    enrolledCourseIds: []
  };

  // 3. Create the record in the users_profiles collection
  try {
    const newProfile = await $db.records.create('users_profiles', profilePayload);
    console.log(`[after_user_create] Successfully seeded users_profiles record (ID: ${newProfile.id}) for user_id: ${user.id}`);
  } catch (err) {
    console.error(`[after_user_create] Failed to seed users_profiles collection: ${err}`);
  }
}

export default async function (req) {
  const body = await req.json();
  const { assignmentId } = body;

  // 1. Resolve and validate the student caller's session claims
  // Extract User ID from the JWT Authorization token
  const authHeader = req.headers.get("authorization") || req.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }

  const token = authHeader.split(" ")[1];
  let userId;
  try {
    const payloadSegment = token.split(".")[1];
    const decodedPayload = JSON.parse($util.base64Decode(payloadSegment));
    userId = Number(decodedPayload.uid);
  } catch (e) {
    return new Response(JSON.stringify({ error: "Invalid token" }), { status: 401 });
  }

  if (!userId) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }
  const callerId = userId; // This is the core auth user ID (users.id)

  // 2. Fetch the corresponding Assignment
  const assignment = await $db.records.get("assignments", assignmentId);
  if (!assignment) {
    return new Response(JSON.stringify({ error: "Assignment not found" }), { status: 404 });
  }

  // 3. Resolve the student caller's users_profiles record ID using their auth user ID
  const studentProfileRes = await $db.records.list("users_profiles", {
    filter: JSON.stringify({ user_id: callerId })
  });
  const studentProfile = studentProfileRes.items[0];
  if (!studentProfile) {
    return new Response(JSON.stringify({ error: "Student profile not found" }), { status: 404 });
  }

  const studentProfileId = studentProfile.id; // This is their users_profiles.id

  // 4. Verify that the caller is indeed the student who posted this assignment
  if (String(assignment.data.studentId) !== String(studentProfileId)) {
    return new Response(JSON.stringify({ error: `Access Denied: Only the student owner can release escrow` }), { status: 403 });
  }

  if (assignment.data.status !== "completed") {
    return new Response(JSON.stringify({ error: "Assignment must be completed by tutor before releasing funds" }), { status: 400 });
  }

  // 5. Find the matching escrow transaction
  const paymentsRes = await $db.records.list("payments", {
    filter: JSON.stringify({ assignmentId: assignmentId, status: "escrow" })
  });
  const payment = paymentsRes.items[0];
  if (!payment) {
    return new Response(JSON.stringify({ error: "Active escrow ledger entry not found" }), { status: 404 });
  }

  // 6. Fetch the Tutor profile to credit
  const tutorProfile = await $db.records.get("users_profiles", assignment.data.tutorId);
  if (!tutorProfile) {
    return new Response(JSON.stringify({ error: "Tutor profile not found" }), { status: 404 });
  }

  // 7. Commit Privileged Actions (Admin Context)
  // A. Update Payment Status to 'released'
  await $db.records.update("payments", payment.id, { status: "released" });

  // B. Update Assignment Status to 'paid'
  await $db.records.update("assignments", assignmentId, { status: "paid" });

  // C. Credit Tutor wallet balance & completedTasks count
  const currentBalance = Number(tutorProfile.data.balance) || 0;
  const completedCount = Number(tutorProfile.data.completedTasks) || 0;
  await $db.records.update("users_profiles", assignment.data.tutorId, {
    balance: currentBalance + Number(payment.data.amount),
    completedTasks: completedCount + 1
  });

  return new Response(JSON.stringify({ success: true, message: "Escrow successfully released to tutor" }));
}

export default async function(req) {
  // Fetch up to 1000 tutor profiles
  const res = await $db.records.list('users_profiles', { 
    limit: 1000, 
    filter: { role: 'tutor' } 
  });

  const expertiseSet = new Set();

  // Extract all unique expertise tags
  for (const item of res.items) {
    if (item.data.expertise && Array.isArray(item.data.expertise)) {
      item.data.expertise.forEach(exp => {
        if (exp && typeof exp === 'string') {
          expertiseSet.add(exp.trim());
        }
      });
    }
  }

  // Return sorted array
  const sortedExpertise = Array.from(expertiseSet).sort();

  return new Response({ expertise: sortedExpertise });
}

export default async function(req) {
  // 1. Fetch Categories dynamically from the Collection Schema
  const cols = await $db.collections.list();
  const courseCol = cols.find(c => c.name === "courses");
  const categories = courseCol?.schema?.fields?.category?.options || [
    "Computer Science",
    "Mathematics",
    "Engineering"
  ];

  // 2. Fetch up to 1000 distinct course codes from actual records
  const coursesRes = await $db.records.list("courses", { limit: 1000 });
  const codeSet = new Set();
  for (const item of coursesRes.items) {
    if (item.data.code) {
      codeSet.add(item.data.code.trim().toUpperCase());
    }
  }
  const sortedCodes = Array.from(codeSet).sort();

  return new Response({
    categories: categories,
    codes: sortedCodes
  });
}

export default async function (req) {
  const body = await req.json();
  const { assignmentId, bidId } = body;

  // 1. Resolve and validate the student caller's session claims
  const authHeader = req.headers.get("authorization") || req.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }

  const token = authHeader.split(" ")[1];
  let userId;
  try {
    const payloadSegment = token.split(".")[1];
    const decodedPayload = JSON.parse($util.base64Decode(payloadSegment));
    userId = Number(decodedPayload.uid);
  } catch (e) {
    return new Response(JSON.stringify({ error: "Invalid token" }), { status: 401 });
  }

  if (!userId) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), { status: 401 });
  }
  const callerId = userId; // This is the auth user ID


  // 2. Fetch the student's users_profiles record
  const studentProfileRes = await $db.records.list("users_profiles", {
    filter: JSON.stringify({ user_id: callerId })
  });
  const studentProfile = studentProfileRes.items[0];
  if (!studentProfile) {
    return new Response(JSON.stringify({ error: "Student profile not found" }), { status: 404 });
  }
  const studentProfileId = studentProfile.id;

  // 3. Fetch the Bid record
  const bid = await $db.records.get("bids", bidId);
  if (!bid) {
    return new Response(JSON.stringify({ error: "Bid not found" }), { status: 404 });
  }

  // 4. Fetch the Assignment record
  const assignment = await $db.records.get("assignments", assignmentId);
  if (!assignment) {
    return new Response(JSON.stringify({ error: "Assignment not found" }), { status: 404 });
  }

  // 5. Verification checks
  if (String(assignment.data.studentId) !== String(studentProfileId)) {
    return new Response(JSON.stringify({
      error: `Access Denied: Only the student owner can accept proposals ${assignment.data.studentId} studentProfileId::${studentProfileId}`
    }), { status: 403 });
  }

  const studentBalance = Number(studentProfile.data.balance) || 0;
  const bidAmount = Number(bid.data.amount);

  if (studentBalance < bidAmount) {
    return new Response(JSON.stringify({ error: "Insufficient wallet balance. Please add funds using the Payment Gateway first!" }), { status: 400 });
  }

  // 6. Commit Privileged Actions (Admin Context)
  // A. Deduct funds from Student Balance
  await $db.records.update("users_profiles", studentProfileId, {
    balance: studentBalance - bidAmount
  });

  // B. Create Escrow Payment record
  const transaction = {
    assignmentId,
    assignmentTitle: assignment.data.title,
    studentId: studentProfileId,
    studentName: studentProfile.data.name,
    tutorId: bid.data.tutorId,
    tutorName: bid.data.tutorName,
    amount: bidAmount,
    status: 'escrow',
    stripePaymentId: 'ch_stripe_' + $util.randomHex(8), // <--- FIXED: Fully compatible native random hex
    createdAt: new Date().toISOString()
  };

  await $db.records.create("payments", transaction);

  // C. Transition Assignment State to Active
  await $db.records.update("assignments", assignmentId, {
    tutorId: bid.data.tutorId,
    tutorName: bid.data.tutorName,
    status: 'active'
  });

  return new Response(JSON.stringify({ success: true, tutorId: bid.data.tutorId }));
}
